import java.util.*;class LongestConsecutive{public static void main(String[]a){Scanner s=new Scanner(System.in);int n=s.nextInt();int[] arr=new int[n];Set<Integer> set=new HashSet<>();for(int i=0;i<n;i++){arr[i]=s.nextInt();set.add(arr[i]);}int max=0;for(int x:set){if(!set.contains(x-1)){int y=x,len=1;while(set.contains(y+1)){y++;len++;}max=Math.max(max,len);}}System.out.println(max);}}